var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안젤라 씨 덕분에 당장 급한 불은 끄긴 했는데…….","JPN":"アンジェラさんのおかげで急場はしのげましたけど……","ENG":"Thanks to Angela, the fire was put out right away.","TWN":"安潔拉小姐，謝謝你的神救援……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저거…… 건물이 무너지는 거 맞죠? 반군들이 폭탄이라도 터뜨린 건가?","JPN":"あれ……建物が崩れてるんですよね？　反乱軍が爆弾でも爆発させたのかな？","ENG":"That... That building is collapsing, right? Did the rebels detonate a bomb or something?","TWN":"那是……整棟建築物倒塌？叛軍是有引爆炸彈嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아니야. 이 느낌은…….","JPN":"違う。この感じは……","ENG":"That’s not it. This feeling...","TWN":"不對，這感覺……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만요. 지금 쓰러진 건물, 우리와 그렇게 멀지 않은 곳인 것 같은데…….","JPN":"ちょっと待ってください。今崩れた建物、私たちの位置とそう遠くない場所のようですけど……","ENG":"Wait a second. That building doesn’t seem all that far from us...","TWN":"等等，那棟倒塌的建築物好像離我們不遠……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"오늘은 공기가 많이 나쁘네……. 감기 안 걸리게 집으로 가야겠어요.","JPN":"今日は空気が良くないわね……風邪を引かないように家に帰りましょう。","ENG":"The air quality is so bad today... We should go home so we don’t catch a cold.","TWN":"今天的空氣不太好……我們趕快回家才不會感冒。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어디로 갈지는 모르겠고 일단 피하기나 하죠!","JPN":"どこへ行くかはわかりませんけど、まずは避難しましょう！","ENG":"I don’t where we’re going, but let’s just avoid that area for now!","TWN":"我不知道還能去哪裡，總之先躲好吧！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"커윽……! 으……!","JPN":"くうっ……！　う……！","ENG":"Kagh...! Ugh...!","TWN":"唔……！呃……！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨?!","JPN":"レアさん！？","ENG":"Leah?!","TWN":"蕾亞小姐？！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아!!","JPN":"レア！！","ENG":"Leah!!","TWN":"蕾亞！！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"세상에……. 온몸이 만신창이야.","JPN":"そんな……全身がボロボロよ。","ENG":"Oh my... Her entire body is in tatters.","TWN":"怎麼會這樣……你傷得好嚴重！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아, 눈 좀 떠 봐! 레아!!","JPN":"レア、目を開けて！　レア！！","ENG":"Leah, open your eyes! Leah!!","TWN":"蕾亞，睜開眼睛！蕾亞！！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"안…… 젤라……?","JPN":"アン……ジェラ……？","ENG":"Angela...?","TWN":"安……潔拉……？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜 아직도……. 여기 있는 거야? 어서 도망치지 않고……!","JPN":"どうしてまだ……ここにいるの？　早く逃げないと……！","ENG":"Why... Why are you still here? You should run...!","TWN":"你們……怎麼還在這裡？快逃……！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"필사적인 저항이로군.","JPN":"必死な抗いだ。","ENG":"Such desperate resistance.","TWN":"看來你是打算誓死抵抗是嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 안식을 거부하기에는 부질없도다.","JPN":"だが、安息を拒むには儚い限りであるな。","ENG":"However, eternal rest is inevitable.","TWN":"不過也只是浪費力氣。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐, 뭔데 또? 로봇, 아니, 사람인가……?","JPN":"ま、また何？　ロボット、いや、人……？","ENG":"Wha-What is that? A robot, no, a human...?","TWN":"你又是什麼誰？機器人？還是人……？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};